.tb-glass-widget-container {
  position: relative;
  width: 100%;
  height: 100%;
  box-sizing: border-box;
  padding: clamp(16px, 2.5vw, 24px);
  background: rgba(43, 50, 65, 0.6);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border-radius: clamp(12px, 1.5vw, 16px);
  display: flex;
  flex-direction: column;
  font-family: 'Roboto', sans-serif;
  overflow: hidden;
  color: #FFFFFF;
}

.tb-bus-header { display: flex; flex-wrap: wrap; gap: 24px; align-items: center; justify-content: space-between; width: 100%; }
.tb-header-section { display: flex; align-items: center; gap: 16px; }
.tb-select-section { flex-direction: column; align-items: flex-start; gap: 6px; }
.tb-label { font-size: var(--label-size, 0.75rem); font-weight: 600; color: rgba(255, 255, 255, 0.5); text-transform: uppercase; }

/* Custom Dropdown Styling Inherited from Car Widget */
.custom-select { position: relative; font-family: inherit; font-size: clamp(13px, 3.5cqi, 15px); user-select: none; min-width: 200px; }
.select-selected { background: rgba(15, 20, 30, 0.6); border: 1px solid rgba(255, 255, 255, 0.1); color: #ffffff; cursor: pointer; transition: all 0.2s ease; box-shadow: 0 2px 12px rgba(255, 255, 255, 0.15); display: flex; align-items: center; box-sizing: border-box; height: 36px; padding: 0 32px 0 16px; border-radius: 8px; font-weight: 500; background-image: url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='white' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e"); background-repeat: no-repeat; background-position: right 10px center; background-size: 14px; }
.select-selected:hover { background-color: rgba(255,255,255,0.1); box-shadow: 0 4px 16px rgba(255, 255, 255, 0.25); transform: translateY(-1px); }
.custom-select.open .select-selected { background-color: rgba(255,255,255,0.1); box-shadow: 0 4px 16px rgba(255, 255, 255, 0.25); background-image: url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='white' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'%3e%3cpolyline points='18 15 12 9 6 15'%3e%3c/polyline%3e%3c/svg%3e"); }
.select-items { position: absolute; top: 100%; left: 0; min-width: 100%; z-index: 99; margin-top: 8px; background-color: rgba(15, 23, 42, 0.95); border: 1px solid rgba(255, 255, 255, 0.1); backdrop-filter: blur(16px); border-radius: 12px; overflow: hidden; box-shadow: 0 10px 30px rgba(0,0,0,0.5); opacity: 0; transform: translateY(-10px) scale(0.98); pointer-events: none; transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); }
.custom-select.open .select-items { opacity: 1; transform: translateY(0) scale(1); pointer-events: auto; }
.select-items div { color: #ffffff; padding: 10px 16px; cursor: pointer; border-bottom: 1px solid rgba(255,255,255,0.05); transition: background 0.2s ease, padding-left 0.2s ease; white-space: nowrap; }
.select-items div:last-child { border-bottom: none; }
.select-items div:hover { background-color: rgba(255,255,255,0.1); padding-left: 20px; }
.select-items div.same-as-selected { background-color: rgba(255,255,255,0.05); color: #3b82f6; font-weight: 600;}

.tb-main-info { flex: 1; min-width: 280px; }
.tb-bus-icon-bg { background: #F97316; width: 48px; height: 48px; border-radius: 12px; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.tb-icon-svg { width: 60%; height: 60%; }
.tb-info-text { display: flex; flex-direction: column; gap: 4px; }
.tb-title-row { display: flex; align-items: center; gap: 12px; }
.tb-widget-title { font-size: var(--title-size, 1.3rem); font-weight: 600; }
.tb-badge { font-size: 0.65rem; font-weight: 700; padding: 2px 8px; border-radius: 4px; text-transform: uppercase; letter-spacing: 0.5px; }

.badge-delayed { background: rgba(245, 158, 11, 0.15); color: #F59E0B; border: 1px solid rgba(245, 158, 11, 0.3); }
.badge-completed { background: rgba(16, 185, 129, 0.15); color: #10B981; border: 1px solid rgba(16, 185, 129, 0.3); }
.badge-incident { background: rgba(239, 68, 68, 0.15); color: #EF4444; border: 1px solid rgba(239, 68, 68, 0.3); }

.tb-subtitle-row { font-size: 0.9rem; color: rgba(255, 255, 255, 0.6); }
.tb-stats-section { gap: 24px; }
.tb-stat-block { display: flex; flex-direction: column; gap: 4px; }
.tb-stat-value { font-size: 0.95rem; font-weight: 500; }
.tb-truncate { max-width: 180px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.tb-occupancy { display: flex; align-items: center; gap: 6px; font-weight: 600; }
.tb-occupancy svg { width: 16px; height: 16px; }

.tb-divider { height: 1px; background: rgba(255, 255, 255, 0.08); margin: 20px 0; width: 100%; }

.tb-logs-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; }
.tb-logs-title { display: flex; align-items: center; gap: 8px; font-weight: 600; font-size: 1.05rem; }
.tb-logs-title svg { width: 18px; height: 18px; color: #8B5CF6; }

/* REPLACED FLEX WITH GRID - Mirrors Car Widget Responsiveness */
.tb-logs-scroll-container { 
  display: grid; 
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); 
  gap: 16px; 
  overflow-y: auto; 
  padding-bottom: 16px; 
  flex: 1; 
  align-content: start;
}

.tb-logs-scroll-container::-webkit-scrollbar { width: 8px; height: 8px; }
.tb-logs-scroll-container::-webkit-scrollbar-track { background: rgba(0, 0, 0, 0.2); border-radius: 4px; }
.tb-logs-scroll-container::-webkit-scrollbar-thumb { background: rgba(255, 255, 255, 0.3); border-radius: 4px; }

@keyframes slideUpFade { 0% { opacity: 0; transform: translateY(20px); } 100% { opacity: 1; transform: translateY(0); } }

/* Removed min-width as the CSS Grid handles sizing now */
.tb-log-card {
  background: rgba(255, 255, 255, 0.04); border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 12px; padding: 16px; display: flex; flex-direction: column; gap: 12px;
  opacity: 0; transform: translateY(20px); animation: slideUpFade 0.4s ease forwards;
  transition: transform 0.3s ease, background-color 0.3s ease, border 0.3s ease;
  cursor: pointer;
}
.tb-log-card:hover { transform: translateY(-5px); background-color: rgba(255, 255, 255, 0.12); }
.tb-card-active { border: 1px solid #8B5CF6; background: rgba(139, 92, 246, 0.1); }

.tb-card-top { display: flex; justify-content: space-between; align-items: center; font-size: 0.8rem; color: rgba(255, 255, 255, 0.6); }
.tb-card-name { font-weight: 600; font-size: 1rem; color: white; }
.tb-card-details { display: flex; flex-direction: column; gap: 6px; font-size: 0.85rem; color: rgba(255, 255, 255, 0.6); }
.tb-detail-row { display: flex; align-items: center; gap: 8px; }
.tb-detail-row svg { width: 14px; height: 14px; }

.tb-widget-content.layout-vertical .tb-bus-header { flex-direction: column; align-items: flex-start; }
.tb-widget-content.layout-vertical .tb-stats-section { width: 100%; justify-content: space-between; }

descriptor.controllerScript:
self.onInit = function() {
    console.log("%c[Widget 1] 🚀 WIDGET BOOTING (Thin Client Mode)", "color: #007FFF; font-weight: bold;");
    
    try {
        self.container = self.ctx.$container[0];

        self.elements = {
            busSelect: self.container.querySelector('#bus-selector-custom'),
            busSelectSelected: self.container.querySelector('.select-selected'),
            busSelectItems: self.container.querySelector('.select-items'),
            
            busNameTitle: self.container.querySelector('#bus-name-title'),
            busStatus: self.container.querySelector('#bus-status'),
            busId: self.container.querySelector('#bus-id'),
            busDriver: self.container.querySelector('#bus-driver'),
            busRoute: self.container.querySelector('#bus-route'),
            busOccupancy: self.container.querySelector('#bus-occupancy'),
            logsContainer: self.container.querySelector('#logs-container')
        };

        self.entitiesData = {}; 
        self.selectedBusName = null;
        self.busMemory = {}; 
        self.lastLogsHash = ""; 
        self.activeTripId = null; 

        if (self.elements.busSelectSelected) {
            self.elements.busSelectSelected.addEventListener('click', function(e) {
                e.stopPropagation();
                if (self.elements.busSelect) self.elements.busSelect.classList.toggle('open');
            });
        }

        self.container.addEventListener('click', function(e) {
            if (!e.target.closest('.custom-select') && self.elements.busSelect) {
                self.elements.busSelect.classList.remove('open');
            }
        });

        self.setupResizeObserver();
        
    } catch (e) {
        console.error("[Widget 1] 🛑 CRASH IN onInit:", e);
    }
};

self.onLatestDataUpdated = function() {};

self.setupResizeObserver = function() {
    self.resizeObserver = new ResizeObserver(entries => {
        for (let entry of entries) {
            const w = entry.contentRect.width;
            if (w < 600) self.container.classList.add('layout-vertical');
            else self.container.classList.remove('layout-vertical');
        }
    });
    self.resizeObserver.observe(self.container);
};

self.onDataUpdated = function() {
    if (!self.ctx.data || !Array.isArray(self.ctx.data) || self.ctx.data.length === 0) return;

    try {
        let groupedData = {};
        let entityNames = new Set();

        self.ctx.data.forEach((ds) => {
            if (!ds.datasource) return;
            
            let eName = ds.datasource.entityName;
            let eType = ds.datasource.entityType;
            
            // === THE FIX: Safely extract entityId ===
            let eId = ds.datasource.entityId;
            if (eId && typeof eId === 'object' && eId.id) {
                eId = eId.id;
            } else if (!eId && ds.datasource.entity && ds.datasource.entity.id) {
                eId = ds.datasource.entity.id;
            }
            
            let key = ds.dataKey.name;
            
            entityNames.add(eName);
            if (!groupedData[eName]) {
                groupedData[eName] = { latest: {}, trips: [], entityId: eId, entityType: eType };
            }
            
            if (ds.data && ds.data.length > 0) {
                let latestValue = ds.data[ds.data.length - 1][1];
                groupedData[eName].latest[key] = latestValue;
                
                if (key === 'trip_summary') {
                    ds.data.forEach(point => {
                        try {
                            let parsed = typeof point[1] === 'string' ? JSON.parse(point[1]) : point[1];
                            if (parsed && parsed.start_time && parsed.end_time) {
                                // Prevent pushing duplicates if ThingsBoard sends overlapping timeseries chunks
                                if (!groupedData[eName].trips.some(t => t.start_time === parsed.start_time)) {
                                    groupedData[eName].trips.push(parsed);
                                }
                            }
                        } catch(err) { console.error("[Widget 1] JSON Parse Error:", err); }
                    });
                }
            }
        });

        self.entitiesData = groupedData;
        
        if (!self.allSeenEntities) self.allSeenEntities = new Set();
        Array.from(entityNames).forEach(name => self.allSeenEntities.add(name)); 
        let allEntitiesArray = Array.from(self.allSeenEntities).sort();
        
        if (self.elements.busSelectItems) {
            let currentOptions = Array.from(self.elements.busSelectItems.querySelectorAll('div')).map(div => div.getAttribute('data-value'));

            if (currentOptions.length !== allEntitiesArray.length) {
                self.elements.busSelectItems.innerHTML = ''; 
                allEntitiesArray.forEach(name => {
                    let div = document.createElement('div');
                    div.setAttribute('data-value', name);
                    div.textContent = name;
                    
                    div.addEventListener('click', function(e) {
                        e.stopPropagation();
                        if (self.elements.busSelect) self.elements.busSelect.classList.remove('open');
                        
                        if (self.selectedBusName !== name) {
                            self.selectedBusName = name;
                            self.lastLogsHash = ""; 
                            self.activeTripId = null; 
                            self.renderBusData();
                        }
                    });
                    self.elements.busSelectItems.appendChild(div);
                });
            }
        }

        if (!self.selectedBusName && allEntitiesArray.length > 0) {
            self.selectedBusName = allEntitiesArray[0];
            self.lastLogsHash = ""; 
        }

        if (self.selectedBusName && self.elements.busSelectSelected) {
            self.elements.busSelectSelected.textContent = self.selectedBusName;
            if (self.elements.busSelect) self.elements.busSelect.setAttribute('data-value', self.selectedBusName);
        }

        allEntitiesArray.forEach(busName => {
            if (!self.busMemory[busName]) self.busMemory[busName] = { logs: [] };
            
            let rawTrips = groupedData[busName].trips || [];
            if (rawTrips.length > 0) {
                rawTrips.sort((a, b) => b.end_time - a.end_time);
                
                self.busMemory[busName].logs = rawTrips.map(trip => {
                    let startStr = new Date(trip.start_time).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
                    let endStr = new Date(trip.end_time).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
                    
                    return {
                        isRealtime: false,
                        date: new Date(trip.end_time).toLocaleDateString(),
                        status: "COMPLETED",
                        statusClass: "badge-completed",
                        name: "Completed Route",
                        time: startStr + " - " + endStr,
                        detail: "Trip Logged",
                        startTime: trip.start_time,
                        endTime: trip.end_time
                    };
                });
                
                if (self.busMemory[busName].logs.length > 15) {
                    self.busMemory[busName].logs = self.busMemory[busName].logs.slice(0, 15);
                }
            }
        });

        self.renderBusData();

    } catch (e) {
        console.error("[Widget 1] 🛑 CRASH IN onDataUpdated:", e);
    }
};

self.renderLogs = function(logs) {
    if (!self.elements.logsContainer) return;
    
    if (logs.length === 0) {
        self.elements.logsContainer.innerHTML = '';
        self.lastLogsHash = "";
        return;
    }

    let currentHash = logs.map(l => l.name + l.time + l.status).join('_');
    if (self.lastLogsHash === currentHash) return; 
    
    self.lastLogsHash = currentHash;
    self.elements.logsContainer.innerHTML = '';

    let activeExists = logs.some(l => (l.startTime + "_" + l.endTime) === self.activeTripId);

    logs.forEach((log, index) => {
        let tripId = log.startTime + "_" + log.endTime; 
        
        if (!activeExists && index === 0) {
            self.activeTripId = tripId;
            activeExists = true; 
        }

        const card = document.createElement('div');
        card.className = 'tb-log-card';
        card.style.animationDelay = `${index * 0.1}s`;
        
        if (self.activeTripId === tripId) card.classList.add('tb-card-active'); 
        
        card.innerHTML = `
            <div class="tb-card-top">
                <span>${log.date}</span>
                <span class="tb-badge ${log.statusClass}">${log.status}</span>
            </div>
            <div class="tb-card-name">${log.name}</div>
            <div class="tb-card-details">
                <div class="tb-detail-row">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg>
                    <span>${log.time}</span>
                </div>
                <div class="tb-detail-row">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle><path d="M23 21v-2a4 4 0 0 0-3-3.87"></path><path d="M16 3.13a4 4 0 0 1 0 7.75"></path></svg>
                    <span>${log.detail}</span>
                </div>
            </div>
        `;
            
        card.addEventListener('click', function() {
            document.querySelectorAll('.tb-log-card').forEach(c => c.classList.remove('tb-card-active'));
            card.classList.add('tb-card-active');
            self.activeTripId = tripId;

            let selectedBus = self.entitiesData[self.selectedBusName];
            
            if (selectedBus && selectedBus.entityId) {
                let tripStartMs = log.startTime  ;//- 10000;
                let tripEndMs = log.endTime  ;// + 9000;
                
                let settings = self.ctx.settings || {};
                let eventName = settings.broadcastEventName || 'busTripSelected';
                let keyStart = settings.payloadKeyStart || 'startTs';
                let keyEnd = settings.payloadKeyEnd || 'endTs';
                let keyDevice = settings.payloadKeyDevice || 'deviceId';

                let tripData = {};
                tripData[keyStart] = tripStartMs;
                tripData[keyEnd] = tripEndMs;
                tripData[keyDevice] = selectedBus.entityId;

                console.log(`[Widget 1] 📢 Broadcasting trip for Map. Event: '${eventName}'`, tripData);
                window.dispatchEvent(new CustomEvent(eventName, { detail: tripData }));
            } else {
                console.warn(`[Widget 1] ⚠️ Cannot broadcast: Missing entityId for bus`, self.selectedBusName);
            }
        });

        self.elements.logsContainer.appendChild(card);
    });
};

self.renderBusData = function() {
    if (!self.selectedBusName || !self.entitiesData[self.selectedBusName]) return;

    let latestData = self.entitiesData[self.selectedBusName].latest;
    let memory = self.busMemory[self.selectedBusName] || { logs: [] };

    if (self.elements.busNameTitle) self.elements.busNameTitle.textContent = self.selectedBusName;
    if (self.elements.busId) self.elements.busId.textContent = self.selectedBusName;

    if (latestData.motion_status && self.elements.busStatus) {
        let sensorStatus = String(latestData.motion_status).toLowerCase();
        self.elements.busStatus.className = 'tb-badge'; 
        
        if (sensorStatus === 'moving') {
            self.elements.busStatus.textContent = 'IN TRANSIT';
            self.elements.busStatus.classList.add('badge-completed'); 
        } else if (sensorStatus === 'stopped' || sensorStatus === 'unset') {
            self.elements.busStatus.textContent = 'PARKED';
            self.elements.busStatus.classList.add('badge-delayed'); 
        } else {
            self.elements.busStatus.textContent = sensorStatus.toUpperCase();
            self.elements.busStatus.classList.add('badge-incident'); 
        }
    }

    if (self.elements.busDriver) self.elements.busDriver.textContent = latestData.driverName || 'No Driver Set';
    if (self.elements.busRoute) self.elements.busRoute.textContent = latestData.routeText || 'No Route Set';
    if (self.elements.busOccupancy) self.elements.busOccupancy.textContent = `38/40`;

    if (self.elements.logsContainer) {
        self.renderLogs(memory.logs);
    }
};

self.typeParameters = function() {
    return {
        hasAdditionalLatestDataKeys: true, 
        previewWidth: '80%',
    };
};

self.onDestroy = function() {
    if (self.resizeObserver) self.resizeObserver.disconnect();
};

